function LogoConcepts() {
  const [active, setActive] = React.useState(0);
  const concepts = [
    { name: 'Minimal', fg: '#0f172a', bg: '#f8fafc' },
    { name: 'Vibrant', fg: '#ffffff', bg: '#2563eb' },
    { name: 'Warm', fg: '#431407', bg: '#ffedd5' },
    { name: 'Dark', fg: '#22d3ee', bg: '#0f172a' }
  ];

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#ffffff', borderRadius: 12, height: '100%', display: 'flex', flexDirection: 'column', color: '#1e293b' }}>
      <h2 style={{ margin: '0 0 12px', fontSize: 18 }}>Logo Concepts</h2>
      <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', borderRadius: 8, background: concepts[active].bg, color: concepts[active].fg, transition: 'all 0.3s' }}>
        <div style={{ textAlign: 'center' }}>
          <div style={{ fontSize: 36, fontWeight: 800, letterSpacing: -1 }}>BRAND</div>
          <div style={{ fontSize: 12, letterSpacing: 3, opacity: 0.8 }}>LOGO CONCEPT</div>
        </div>
      </div>
      <div style={{ display: 'flex', gap: 8, marginTop: 12, justifyContent: 'center' }}>
        {concepts.map((c, i) => (
          <button
            key={i}
            onClick={() => setActive(i)}
            style={{
              padding: '6px 12px',
              borderRadius: 6,
              border: '1px solid #e2e8f0',
              background: active === i ? '#1e293b' : '#fff',
              color: active === i ? '#fff' : '#1e293b',
              fontSize: 12,
              cursor: 'pointer'
            }}
          >
            {c.name}
          </button>
        ))}
      </div>
    </div>
  );
}
render(<LogoConcepts/>);
